from datetime import datetime
from pydantic import BaseModel, Field


class LoginRequest(BaseModel):
    """Request schema for /api/auth/login endpoint."""

    username: str = Field(..., min_length=1, max_length=255, description="User's username")
    password: str = Field(..., min_length=1, description="User's password")

    model_config = {
        "json_schema_extra": {
            "examples": [
                {"username": "john_doe", "password": "secretpassword123"}
            ]
        }
    }


class TokenResponse(BaseModel):
    """Response schema for successful authentication."""

    access_token: str = Field(..., description="JWT access token")
    token_type: str = Field(default="bearer", description="Token type")

    model_config = {
        "json_schema_extra": {
            "examples": [
                {"access_token": "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...", "token_type": "bearer"}
            ]
        }
    }


class RefreshRequest(BaseModel):
    """Request schema for /api/auth/refresh endpoint."""

    token: str = Field(..., description="Valid JWT token to refresh")

    model_config = {
        "json_schema_extra": {
            "examples": [
                {"token": "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..."}
            ]
        }
    }


class ErrorResponse(BaseModel):
    """Standard error response schema."""

    detail: str = Field(..., description="Error message")

    model_config = {
        "json_schema_extra": {
            "examples": [
                {"detail": "Invalid credentials"},
                {"detail": "Rate limit exceeded. Try again later."}
            ]
        }
    }
